const ENCRYPTED_PAYLOAD = {"kdf": "PBKDF2-SHA256", "iterations": 250000, "salt": "P6fNt37tn7wUzviwVQ+65g==", "nonce": "wo901rsaeKr8nkkP", "ciphertext": ""};

const form = document.getElementById("password-form");
const passwordInput = document.getElementById("password");
const statusEl = document.getElementById("status");
const gate = document.getElementById("gate");
const app = document.getElementById("app");
const content = document.getElementById("content");
const search = document.getElementById("search");
const backButton = document.getElementById("back-button");

function b64ToBytes(value) {
  const bin = atob(value);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return bytes;
}

async function deriveKey(password, salt, iterations) {
  const baseKey = await crypto.subtle.importKey(
    "raw",
    new TextEncoder().encode(password),
    "PBKDF2",
    false,
    ["deriveKey"]
  );
  return crypto.subtle.deriveKey(
    { name: "PBKDF2", salt, iterations, hash: "SHA-256" },
    baseKey,
    { name: "AES-GCM", length: 256 },
    false,
    ["decrypt"]
  );
}

async function unlock(password) {
  const salt = b64ToBytes(ENCRYPTED_PAYLOAD.salt);
  const nonce = b64ToBytes(ENCRYPTED_PAYLOAD.nonce);
  const ciphertext = b64ToBytes(ENCRYPTED_PAYLOAD.ciphertext);
  const key = await deriveKey(password, salt, ENCRYPTED_PAYLOAD.iterations);
  const plain = await crypto.subtle.decrypt({ name: "AES-GCM", iv: nonce }, key, ciphertext);
  return new TextDecoder().decode(plain);
}

form.addEventListener("submit", async (event) => {
  event.preventDefault();
  statusEl.textContent = "Verificando...";
  try {
    const html = await unlock(passwordInput.value);
    content.innerHTML = html;
    gate.hidden = true;
    app.hidden = false;
    statusEl.textContent = "";
    window.scrollTo(0, 0);
  } catch (error) {
    statusEl.textContent = "Senha incorreta.";
    passwordInput.value = "";
    passwordInput.focus();
  }
});

backButton.addEventListener("click", () => {
  if (history.length > 1) history.back();
});

search.addEventListener("input", () => {
  const term = search.value.trim().toLowerCase();
  document.querySelectorAll(".note").forEach((note) => {
    note.hidden = term && !note.textContent.toLowerCase().includes(term);
  });
});
